{
  "activities": [
    {
      "type": "activity",
      "title": "Role Play and Dramatization",
      "unit_name": "Prose",
      "chapter_name": "The Proposal (Play)",
      "details": "Students will enact scenes from the play to understand character dynamics, humor, and dramatic irony."
    },
    {
      "type": "activity",
      "title": "Poetry Recitation with Intonation",
      "unit_name": "Poems",
      "chapter_name": "The Road Not Taken",
      "details": "Students will recite the poem focusing on rhythm, pause, and intonation to convey the poet's mood."
    },
    {
      "type": "activity",
      "title": "Group Discussion on Contemporary Issues",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "The Beggar",
      "details": "Students will discuss the themes of poverty, redemption, and social responsibility based on the text."
    },
    {
      "type": "activity",
      "title": "Listening to Audio Texts",
      "unit_name": "Workbook Units",
      "chapter_name": "Units 1 to 4",
      "details": "Students will listen to authentic audio texts (weather reports, interviews) and retell the content."
    },
    {
      "type": "activity",
      "title": "Speaking Presentation Skills",
      "unit_name": "Workbook Units",
      "chapter_name": "Units 7 to 11",
      "details": "Students will deliver short presentations on topics of mutual interest, focusing on fluency and clarity."
    },
    {
      "type": "activity",
      "title": "Simulating Real Life Situations",
      "unit_name": "Prose",
      "chapter_name": "A Letter to God",
      "details": "Students will simulate a scenario where they write and respond to official communications based on the story."
    },
    {
      "type": "activity",
      "title": "Interpreting Visual Data",
      "unit_name": "Reading Skills",
      "chapter_name": "Case-based factual passage",
      "details": "Students will interpret charts and statistical data from the unseen passage to answer comprehension questions."
    },
    {
      "type": "activity",
      "title": "Debate on Character Traits",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "Bholi",
      "details": "Students will debate the character traits of Sulekha (Bholi) and her transformation."
    }
  ],
  "projects": [
    {
      "title": "Art-Integrated Role Play Project",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "The Proposal (Play)",
      "details": "Create a skit or dramatization of the play 'The Proposal' incorporating art elements like costumes and props to assess listening and speaking skills."
    },
    {
      "title": "Multilingual Literature Appreciation Project",
      "unit_name": "Prose/Poetry Collection",
      "chapter_name": "The Lost Child",
      "details": "Students will research and present on Indian languages and literature, comparing themes with the text 'The Lost Child'."
    },
    {
      "title": "Creative Writing Portfolio",
      "unit_name": "Workbook Units",
      "chapter_name": "Units 1 to 6",
      "details": "Compile a portfolio of creative writing pieces including stories, diary entries, and descriptive paragraphs based on visual cues."
    },
    {
      "title": "Listening and Speaking Skills Assessment Project",
      "unit_name": "Workbook Units",
      "chapter_name": "Units 7 to 11",
      "details": "Conduct a series of interactive speaking activities and listening tasks, assessed using the provided rubric for fluency, pronunciation, and vocabulary."
    }
  ],
  "practicals": [
    {
      "title": "Grammar Transformation Exercise",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Reported Speech",
      "details": "Practical exercise to transform direct speech into reported speech for commands, requests, statements, and questions."
    },
    {
      "title": "Editing and Gap Filling Practice",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Tenses and Modals",
      "details": "Students will edit paragraphs and fill gaps to practice accurate usage of tenses, modals, and punctuation."
    },
    {
      "title": "Visual Data Transcoding",
      "unit_name": "Writing Skills and Grammar",
      "chapter_name": "Analytical Paragraph",
      "details": "Practical task to transcode information from a graph or chart into an analytical paragraph of 100-120 words."
    },
    {
      "title": "Oral Communication Simulation",
      "unit_name": "Workbook Units",
      "chapter_name": "Units 1 to 4",
      "details": "Simulate real-life oral communication scenarios such as interviews or public announcements to practice listening and speaking."
    }
  ]
}
